using namespace std;

class Solution {
public:
    int solve(string text1, string text2) {
        if (text1.length() > text2.length()) {
            return solve(text2, text1);
        }
        int m = text1.length();
        int n = text2.length();
        int[,] dp;
        for (int i = 0; i <= m; i++) {
            for (int j = 0; j <= n; j++) {
                if (i == 0 || j == 0) {
                    dp[i][j] = 0;
                } else if (text1[i-1] == text2[j-1]) {
                    dp[i][j] = dp[i-1][j-1] + 1;
                } else {
                    dp[i][j] = max(dp[i-1][j], dp[i][j-1]);
                }
            }
        }
        return dp[m][n];
    }
};

int main() {
    Solution solution;
    string text1, text2;
    cin >> text1 >> text2;
    cout << solution.solve(text1, text2);
